import { useEffect, useState } from "react";
import API from "../api";

const AdminDashboard = () => {
  const [events, setEvents] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const eventsRes = await API.get("/events");
        const bookingsRes = await API.get("/bookings/all/bookings");
        const paymentsRes = await API.get("/payments/all/payments");
        setEvents(eventsRes.data.events);
        setBookings(bookingsRes.data.bookings);
        setPayments(paymentsRes.data.payments);
      } catch (err) {
        console.log(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) return <p className="text-center mt-10">Loading...</p>;

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6">Admin Dashboard</h1>

      <section className="mb-8">
        <h2 className="text-2xl font-semibold mb-4">Events</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {events.map(e => (
            <div key={e._id} className="bg-white shadow p-4 rounded-lg">
              <h3 className="font-bold">{e.name}</h3>
              <p>Date: {new Date(e.date).toLocaleDateString()}</p>
              <p>Venue: {e.venue}</p>
              <p>Available Seats: {e.availableSeats}</p>
            </div>
          ))}
        </div>
      </section>

      <section className="mb-8">
        <h2 className="text-2xl font-semibold mb-4">Bookings</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {bookings.map(b => (
            <div key={b._id} className="bg-white shadow p-4 rounded-lg">
              <p>Event: {b.event.name}</p>
              <p>User: {b.user.name}</p>
              <p>Tickets: {b.numberOfTickets}</p>
              <p>Status: {b.status}</p>
              <p>Payment: {b.paymentStatus}</p>
            </div>
          ))}
        </div>
      </section>

      <section>
        <h2 className="text-2xl font-semibold mb-4">Payments</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {payments.map(p => (
            <div key={p._id} className="bg-white shadow p-4 rounded-lg">
              <p>User: {p.user.name}</p>
              <p>Event: {p.booking.event.name}</p>
              <p>Amount: ${p.amount}</p>
              <p>Payment Method: {p.paymentMethod}</p>
              <p>Status: {p.status}</p>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default AdminDashboard;
